def test_non_clinician_update_patient_returns_403(guest_client, existing_patient):
    pid = existing_patient["id"]
    payload = {
        "resourceType": "Patient",
        "id": pid,
        "name": [{"family": "ShouldFail"}]
    }
    resp = guest_client.put(
        f"/Patient/{pid}",
        json=payload,
        headers={"Content-Type": "application/fhir+json"}
    )
    assert resp.status_code == 403
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome"

def test_update_patient_stale_version_returns_409(clinician_client, existing_patient):
    pid = existing_patient["id"]
    old_version = existing_patient["meta"]["versionId"]
    stale_etag = f'W/"{old_version}"'

    first_payload = {
        "resourceType": "Patient",
        "id": pid,
        "name": [{"family": "FirstUpdate"}]
    }
    advance = clinician_client.put(
        f"/Patient/{pid}",
        json=first_payload,
        headers={"If-Match": stale_etag, "Content-Type": "application/fhir+json"}
    )
    assert advance.status_code == 200

    stale_payload = {
        "resourceType": "Patient",
        "id": pid,
        "name": [{"family": "StaleUpdate"}]
    }
    resp = clinician_client.put(
        f"/Patient/{pid}",
        json=stale_payload,
        headers={"If-Match": stale_etag, "Content-Type": "application/fhir+json"}
    )
    assert resp.status_code == 409
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome"
